create table if not exists analytics_events ( id uuid default gen_random_uuid() primary key, user_id uuid references profiles(id), event_name text not null, properties jsonb default '{}'::jsonb, session_id text, created_at timestamptz default now() ); create index if not exists idx_analytics_event on analytics_events(event_name); create index if not exists idx_analytics_user on analytics_events(user_id);
